request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?scenario ?name ?dep ?req WHERE {
  ?scenario rdf:type vocab:instance%20specification .
  ?scenario vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(?name), "duration scenario"))

  # Check for dependencies (client/supplier)
  OPTIONAL {
    ?dep rdf:type ?depType .
    FILTER(?depType IN (vocab:satisfy, vocab:verify, vocab:allocate))
    { ?dep vocab:Dependency_client ?scenario . ?dep vocab:Dependency_supplier ?req . }
    UNION
    { ?dep vocab:Dependency_supplier ?scenario . ?dep vocab:Dependency_client ?req . }
  }
}
LIMIT 50
